+            test_name: test_name.to_owned(),
+            passed: steps_error == 0,
+            steps_total: log.entries().len(),
+            steps_ok,
+            steps_error,
+            steps_skip,
+            duration_us: u64::try_from(duration.as_micros()).unwrap_or(u64::MAX),
+            artifacts_dir: artifacts_dir.map(|p| p.display().to_string()),
