+            &device,
+            &validator,
+            test_uuid(),
+            vec![group_cfg],
+            &mut ledger_buf,
+            4,
+        );
+
+        let report = pipeline.scrub_and_recover(&cx).expect("pipeline");
+        assert!(
+            report.is_fully_recovered(),
